def cached(cache, key=hashkey, lock=None):
    """
    Decorador para envolver una función con una llamada que memoriza y guarda  
    los resultados en una caché.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = key(*args, **kwargs)
            if cache_key in cache:
                return cache[cache_key]
            if lock:
                with lock:
                    if cache_key in cache:
                        return cache[cache_key]
                    result = func(*args, **kwargs)
                    cache[cache_key] = result
                    return result
            else:
                result = func(*args, **kwargs)
                cache[cache_key] = result
                return result
        return wrapper
    return decorator

import time
from functools import lru_cache, wraps

def ttl_cache(maxsize=128, ttl=600, timer=time.monotonic, typed=False):
    def decorator(func):
        @lru_cache(maxsize=maxsize, typed=typed)
        def cached_func(*args, **kwargs):
            return func(*args, **kwargs)

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = (args, frozenset(kwargs.items())) if typed else (args, tuple(kwargs.items()))
            current_time = timer()
            if key in wrapper._cache_info:
                last_access_time, result = wrapper._cache_info[key]
                if current_time - last_access_time < ttl:
                    wrapper._cache_info[key] = (current_time, result)
                    return result
                else:
                    del wrapper._cache_info[key]
            result = cached_func(*args, **kwargs)
            wrapper._cache_info[key] = (current_time, result)
            return result

        wrapper._cache_info = {}
        return wrapper
    return decorator

from functools import wraps
from collections import OrderedDict

def mru_cache(maxsize=128, typed=False):
    """
    Decorador para envolver una función con un objeto invocable que memoriza hasta `maxsize` resultados basados en un algoritmo de Más Recientemente Usado (MRU).
    """
    def decorator(func):
        cache = OrderedDict()

        @wraps(func)
        def wrapper(*args, **kwargs):
            if typed:
                key = (args, tuple((k, type(v)) for k, v in sorted(kwargs.items()))
            else:
                key = (args, tuple(sorted(kwargs.items())))

            if key in cache:
                # Move the accessed key to the end to mark it as recently used
                cache.move_to_end(key)
                return cache[key]

            result = func(*args, **kwargs)

            if len(cache) >= maxsize:
                # Remove the least recently used item
                cache.popitem(last=False)

            cache[key] = result
            return result

        return wrapper

    return decorator

