def difference(d1, d2, level=-1):
    """
    Devuelve un diccionario con los elementos de *d1* que no están contenidos en *d2*.

    El parámetro *level* establece la profundidad máxima de recursión. Para recursión infinita, configúralo en -1. Para un nivel 1, si una clave está presente tanto en *d1* como en *d2* pero tiene valores diferentes, se incluye en la diferencia. Consulta :func:`intersection` para más detalles.

    *d1* y *d2* permanecen sin cambios. Sin embargo, *d1* o algunos de sus subdiccionarios pueden ser devueltos directamente. Realiza una copia profunda del resultado cuando sea apropiado.

    .. versionadded:: 0.5  
       Agrega el argumento de palabra clave *level*.
    """
    if level == 0:
        return {k: v for k, v in d1.items() if k not in d2 or d2[k] != v}

    diff = {}
    for k, v in d1.items():
        if k not in d2:
            diff[k] = v
        elif isinstance(v, dict) and isinstance(d2[k], dict) and level != 1:
            sub_diff = difference(v, d2[k], level - 1 if level != -1 else -1)
            if sub_diff:
                diff[k] = sub_diff
        elif v != d2[k]:
            diff[k] = v
    return diff

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Junto con la función :func:`generate_default_observer_schema_list`, esta función se llama de manera recursiva para generar parte de un ``observer_schema`` predeterminado a partir de una parte de un recurso de Kubernetes, definido respectivamente por ``manifest_dict`` o ``manifest_list``.

    Argumentos:
    **manifest_dict (dict):** Recursos parciales de Kubernetes.
    **first_level (bool, opcional):** Si es True, indica que el diccionario representa el esquema completo del observador (observer schema) de un recurso de Kubernetes.

    Retorna:
    **dict:** Esquema parcial generado (`observer_schema`).

    Esta función crea un nuevo diccionario a partir de ``manifest_dict`` y reemplaza todos los valores que no sean listas (`list`) ni diccionarios (`dict`) por ``None``.

    En el caso de un diccionario de ``first_level`` (es decir, un ``observer_schema`` completo para un recurso), los valores de los campos identificadores se copian del archivo de manifiesto.
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            observer_schema[key] = generate_default_observer_schema_list(value)
        else:
            if first_level and key in ['apiVersion', 'kind', 'metadata']:
                observer_schema[key] = value
            else:
                observer_schema[key] = None

    return observer_schema

def generate_default_observer_schema_list(manifest_list):
    """
    Junto con la función :func:`generate_default_observer_schema_dict`, esta función se llama de manera recursiva para generar parte de un ``observer_schema`` predeterminado a partir de una parte de un recurso de Kubernetes, definido respectivamente por ``manifest_dict`` o ``manifest_list``.

    Argumentos:
    **manifest_list (list):** Recursos parciales de Kubernetes.

    Retorna:
    **list:** Esquema parcial generado (`observer_schema`).

    Esta función crea una nueva lista a partir de ``manifest_list`` y reemplaza todos los valores que no sean listas (`list`) ni diccionarios (`dict`) por ``None``.
    """
    observer_schema = []

    for item in manifest_list:
        if isinstance(item, dict):
            observer_schema.append(generate_default_observer_schema_dict(item))
        elif isinstance(item, list):
            observer_schema.append(generate_default_observer_schema_list(item))
        else:
            observer_schema.append(None)

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Junto con :func:``update_last_applied_manifest_dict_from_resp``, esta
    función se llama de forma recursiva para actualizar un ``last_applied_manifest``
    parcial a partir de una respuesta parcial de Kubernetes.

    Argumentos:
        last_applied_manifest (list): ``last_applied_manifest`` parcial que se
            está actualizando.
        observer_schema (list): ``observer_schema`` parcial.
        response (list): respuesta parcial de la API de Kubernetes.

    Esta función recorre todos los campos observados e inicializa su valor en
    ``last_applied_manifest`` si aún no están presentes.
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Junto con :func:``update_last_applied_manifest_list_from_resp``, esta
    función se llama de forma recursiva para actualizar un ``last_applied_manifest``
    parcial a partir de una respuesta parcial de Kubernetes.

    Argumentos:
        last_applied_manifest (dict): ``last_applied_manifest`` parcial que se está
            actualizando.
        observer_schema (dict): ``observer_schema`` parcial.
        response (dict): respuesta parcial de la API de Kubernetes.

    Excepciones:
        KeyError: Si el campo observado no está presente en la respuesta de Kubernetes.

    Esta función recorre todos los campos observados e inicializa su valor en
    ``last_applied_manifest`` si aún no están presentes.
    """
    for key, schema in observer_schema.items():
        if key not in response:
            raise KeyError(f"El campo observado '{key}' no está presente en la respuesta de Kubernetes.")

        if isinstance(schema, dict):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[key], schema, response[key])
        elif isinstance(schema, list):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = []
            update_last_applied_manifest_list_from_resp(last_applied_manifest[key], schema, response[key])
        else:
            if key not in last_applied_manifest:
                last_applied_manifest[key] = response[key]

def generate_default_observer_schema(app):
    """
    Generar el esquema de observador predeterminado para cada recurso de Kubernetes presente en  
    ``spec.manifest`` para el cual no se haya especificado un esquema de observador personalizado.

    Argumentos:
    app(krake.data.kubernetes.Application): La aplicación para la cual se generará un esquema de observador predeterminado.
    """
    default_schema = {
        "type": "object",
        "properties": {
            "apiVersion": {"type": "string"},
            "kind": {"type": "string"},
            "metadata": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "namespace": {"type": "string"}
                },
                "required": ["name"]
            },
            "spec": {"type": "object"},
            "status": {"type": "object"}
        },
        "required": ["apiVersion", "kind", "metadata"]
    }

    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema'):
            resource.observer_schema = default_schema

    return app

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    formatted_sql = sql
    formatted_params = []

    for params in many_params:
        if isinstance(params, dict):
            # Convert dict to list of values in order of keys
            formatted_params.append(list(params.values()))
        elif isinstance(params, (list, tuple)):
            # If it's already a sequence, just append it
            formatted_params.append(params)
        else:
            raise TypeError("params must be a Mapping or Sequence")

    return formatted_sql, formatted_params

def status_str(self, prefix=''):
    """
    Devuelve una cadena con el estado del validador, con un prefijo opcional.
    """
    # Asumiendo que el validador tiene atributos que representan su estado
    status = f"{prefix}Estado del validador: "
    if hasattr(self, 'is_valid'):
        status += "Válido" if self.is_valid else "Inválido"
    if hasattr(self, 'last_checked'):
        status += f", Última verificación: {self.last_checked}"
    if hasattr(self, 'error_message'):
        status += f", Mensaje de error: {self.error_message}"
    return status

def validate(self, inventory, extract_spec_version=False):
    """
    Validar un inventario dado.

    Si `extract_spec_version` es True, entonces se verificará el valor de `type` para determinar
    la versión de la especificación. En el caso de que no exista un valor para `type` o no sea
    válido, se realizarán otras pruebas basadas en la versión proporcionada en `self.spec_version`.
    """
    if extract_spec_version:
        if 'type' in inventory:
            spec_type = inventory['type']
            if spec_type in self.spec_version:
                return self.spec_version[spec_type]
            else:
                # Realizar otras pruebas basadas en self.spec_version
                return self.spec_version.get('default', 'unknown')
        else:
            # Realizar otras pruebas basadas en self.spec_version
            return self.spec_version.get('default', 'unknown')
    else:
        # Validar el inventario sin extraer la versión de la especificación
        return True

def check_digests_present_and_used(self, manifest_files, digests_used):
    """
    Verifique que todos los resúmenes necesarios en el manifiesto estén presentes y se utilicen.
    """
    # Extract all digests from the manifest files
    manifest_digests = set()
    for manifest_file in manifest_files:
        with open(manifest_file, 'r') as file:
            for line in file:
                if 'digest' in line:
                    digest = line.split('digest:')[1].strip()
                    manifest_digests.add(digest)

    # Check if all digests in the manifest are used
    for digest in manifest_digests:
        if digest not in digests_used:
            return False

    # Check if all used digests are in the manifest
    for digest in digests_used:
        if digest not in manifest_digests:
            return False

    return True

def get_logical_path_map(inventory, version):
    """
    Obtén un mapa de las rutas lógicas en el estado hacia los archivos en disco para una versión específica en el inventario.

    Devuelve un diccionario: `logical_path_in_state -> set(content_files)`

    El conjunto de `content_files` puede incluir referencias a archivos duplicados en versiones posteriores a la versión que se está describiendo.
    """
    logical_path_map = {}

    for logical_path, versions_data in inventory.items():
        if version in versions_data:
            content_files = versions_data[version]
            logical_path_map[logical_path] = set(content_files)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Validar el bloque de fijación en el inventario.

    Verificar la estructura del bloque de fijación y asegurarse de que solo se referencien los archivos listados en el manifiesto.
    """
    if not isinstance(fixity, dict):
        raise ValueError("El bloque de fijación debe ser un diccionario.")

    if not isinstance(manifest_files, list):
        raise ValueError("El manifiesto de archivos debe ser una lista.")

    for file_name, checksum in fixity.items():
        if file_name not in manifest_files:
            raise ValueError(f"El archivo '{file_name}' no está listado en el manifiesto.")

        if not isinstance(checksum, str):
            raise ValueError(f"El checksum para el archivo '{file_name}' debe ser una cadena de texto.")

    return True

def fix_namespace_prefix_w(content):
    """
    Convierte el texto que por defecto es 'w:st="' a 'w-st="'
    """
    return content.replace('w:st="', 'w-st="')

def match_pubdate(node, pubdate_xpaths):
    """
    Devuelve la primera coincidencia en la lista de 'pubdate_xpaths'.
    """
    for xpath in pubdate_xpaths:
        match = node.xpath(xpath)
        if match:
            return match[0]
    return None

def pretty(self, indent=0, debug=False):
    """
    Devuelve una representación formateada de manera legible de 'self'.
    """
    if debug:
        print(f"Debug: Indent level = {indent}")

    # Assuming 'self' is a dictionary-like object for this example
    if isinstance(self, dict):
        result = "{\n"
        for key, value in self.items():
            result += " " * (indent + 4) + f"{repr(key)}: "
            if isinstance(value, dict):
                result += value.pretty(indent + 4, debug) if hasattr(value, 'pretty') else pretty(value, indent + 4, debug)
            else:
                result += repr(value)
            result += ",\n"
        result += " " * indent + "}"
        return result
    elif isinstance(self, list):
        result = "[\n"
        for item in self:
            result += " " * (indent + 4)
            if isinstance(item, dict):
                result += item.pretty(indent + 4, debug) if hasattr(item, 'pretty') else pretty(item, indent + 4, debug)
            else:
                result += repr(item)
            result += ",\n"
        result += " " * indent + "]"
        return result
    else:
        return repr(self)

def absorb(self, args):
    """
    Dada una secuencia `args` de expresiones, devuelve una nueva lista de expresiones aplicando absorción y absorción negativa.

    Consulta https://es.wikipedia.org/wiki/Leyes_de_absorci%C3%B3n

    Absorción::

        A & (A | B) = A, A | (A & B) = A

    Absorción negativa::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    def apply_absorption(expr):
        if isinstance(expr, tuple):
            if expr[0] == '&':
                A, B = expr[1], expr[2]
                if isinstance(B, tuple) and B[0] == '|':
                    if B[1] == A:
                        return A
                    elif B[2] == A:
                        return A
                elif isinstance(B, tuple) and B[0] == '&':
                    if B[1] == ('~', A):
                        return ('&', A, B[2])
                    elif B[2] == ('~', A):
                        return ('&', A, B[1])
            elif expr[0] == '|':
                A, B = expr[1], expr[2]
                if isinstance(B, tuple) and B[0] == '&':
                    if B[1] == A:
                        return A
                    elif B[2] == A:
                        return A
                elif isinstance(B, tuple) and B[0] == '|':
                    if B[1] == ('~', A):
                        return ('|', A, B[2])
                    elif B[2] == ('~', A):
                        return ('|', A, B[1])
        return expr

    return [apply_absorption(arg) for arg in args]

def on(self, hook):
    """
    Función decoradora para agregar un nuevo manejador al registro.

    Argumentos:
    hook (HookType): Atributo del hook para el cual se registrará el manejador.

    Retorna:
    callable: Decorador para registrar los listeners para el hook especificado.
    """
    def decorator(func):
        if not hasattr(self, '_handlers'):
            self._handlers = {}
        if hook not in self._handlers:
            self._handlers[hook] = []
        self._handlers[hook].append(func)
        return func
    return decorator

def tzname_in_python2(namefunc):
    """
    Cambiar la salida de unicode a cadenas de bytes en Python 2

    La API tzname() cambió en Python 3. Solía devolver bytes, pero fue modificada
    para devolver cadenas unicode.
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, unicode):
            return result.encode('utf-8')
        return result
    return wrapper

def get_versions():
    """
    Obtén la información de la versión o devuelve el valor predeterminado si no es posible obtenerla.
    """
    import sys
