    elif style == 'patch':
        return f"{pieces['patch']}"
    else:
        raise ValueError(f"Estilo '{style}' no soportado.")

def plus_or_dot(pieces):
    """
    Devuelve un "+" si no tenemos uno ya, de lo contrario, devuelve un "."
    """
    if '+' not in pieces:
        return '+'
    else:
        return '.'

from ruamel.yaml.nodes import ScalarNode, MappingNode

def deep_merge_nodes(nodes):
    merged_nodes = {}

    for key_node, value_node in nodes:
        key = key_node.value

        if key in merged_nodes:
            existing_value_node = merged_nodes[key]

            if isinstance(existing_value_node, MappingNode) and isinstance(value_node, MappingNode):
                # Merge the MappingNodes deeply
                existing_value = existing_value_node.value
                new_value = value_node.value

                # Create a dictionary to hold the merged values
                merged_value = {}
                for k_node, v_node in existing_value:
                    merged_value[k_node.value] = v_node

                for k_node, v_node in new_value:
                    merged_value[k_node.value] = v_node

                # Convert the merged dictionary back to a list of tuples
                merged_value_list = [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in merged_value.items()]
                merged_nodes[key] = MappingNode(tag='tag:yaml.org,2002:map', value=merged_value_list)
            else:
                # If either value is not a MappingNode, the last value prevails
                merged_nodes[key] = value_node
        else:
            merged_nodes[key] = value_node

    # Convert the merged dictionary back to a list of tuples
    result = [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in merged_nodes.items()]
    return result

def parser_flags(parser):
    """
    Dada una instancia de 'argparse.ArgumentParser', devuelve sus banderas de argumentos
    en una cadena separada por espacios.
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

import argparse

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dada una secuencia de argumentos y un diccionario que mapea el nombre de un subparser a una instancia de `argparse.ArgumentParser`, permite que cada subparser solicitado intente analizar todos los argumentos. Esto permite que argumentos comunes como `--repository` sean compartidos entre múltiples subparsers.

    Devuelve el resultado como una tupla que contiene: 
    - Un diccionario que mapea el nombre del subparser a un espacio de nombres (`namespace`) de argumentos analizados.
    - Una lista de argumentos restantes que no fueron reclamados por ningún subparser.
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, subparser in subparsers.items():
        try:
            namespace, remaining = subparser.parse_known_args(remaining_args)
            parsed_args[subparser_name] = namespace
            remaining_args = remaining
        except argparse.ArgumentError:
            continue

    return parsed_args, remaining_args

from ruamel.yaml.nodes import ScalarNode, MappingNode

def deep_merge_nodes(nodes):
    merged_nodes = {}

    for key, value in nodes:
        if key.value in merged_nodes:
            existing_value = merged_nodes[key.value]
            if isinstance(existing_value, MappingNode) and isinstance(value, MappingNode):
                # Merge the MappingNodes
                merged_mapping = {}
                for sub_key, sub_value in existing_value.value:
                    merged_mapping[sub_key.value] = sub_value
                for sub_key, sub_value in value.value:
                    merged_mapping[sub_key.value] = sub_value
                # Convert back to list of tuples
                merged_value = [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v] for k, v in merged_mapping.items()]
                merged_nodes[key.value] = MappingNode(tag='tag:yaml.org,2002:map', value=merged_value)
            else:
                # If not both MappingNodes, the last value prevails
                merged_nodes[key.value] = value
        else:
            merged_nodes[key.value] = value

    # Convert the merged_nodes dictionary back to a list of tuples
    result = [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in merged_nodes.items()]
    return result

def parser_flags(parser):
    """
    Dada una instancia de 'argparse.ArgumentParser', devuelve sus banderas de argumentos en una cadena separada por espacios.
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

import argparse

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dada una secuencia de argumentos y un diccionario que mapea el nombre de un subparser a una instancia de `argparse.ArgumentParser`, permite que cada subparser solicitado intente analizar todos los argumentos. Esto permite que argumentos comunes como "--repository" sean compartidos entre múltiples subparsers.

    Devuelve el resultado como una tupla que contiene: (un diccionario que mapea el nombre del subparser a un espacio de nombres (`namespace`) de argumentos analizados, una lista de argumentos restantes que no fueron reclamados por ningún subparser).
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, subparser in subparsers.items():
        try:
            args, remaining = subparser.parse_known_args(remaining_args)
            parsed_args[subparser_name] = args
            remaining_args = remaining
        except argparse.ArgumentError:
            continue

    return parsed_args, remaining_args

def _dictsum(dicts):
    """
    Combina los valores de los diccionarios proporcionados por el iterable `dicts`.

    >>> _dictsum([{'a': 1, 'b': 2}, {'a': 5, 'b': 0}])
    {'a': 6, 'b': 2}
    """
    result = {}
    for d in dicts:
        for key, value in d.items():
            if key in result:
                result[key] += value
            else:
                result[key] = value
    return result

