import re
from datetime import timedelta

def parse_frequency(frequency):
    """
    Dado un string de frecuencia con un número y una unidad de tiempo, devuelve una instancia correspondiente de 'datetime.timedelta' o 'None' si la frecuencia es 'None' o "always".

    Por ejemplo, dado "3 weeks", devuelve datetime.timedelta(weeks=3).

    Lanza ValueError si la frecuencia proporcionada no puede ser analizada
    """
    if frequency is None or frequency.lower() == "always":
        return None

    pattern = re.compile(r'^(\d+)\s*(second|minute|hour|day|week|month|year)s?$', re.IGNORECASE)
    match = pattern.match(frequency.strip())

    if not match:
        raise ValueError(f"Frecuencia no válida: {frequency}")

    value = int(match.group(1))
    unit = match.group(2).lower()

    if unit == "second":
        return timedelta(seconds=value)
    elif unit == "minute":
        return timedelta(minutes=value)
    elif unit == "hour":
        return timedelta(hours=value)
    elif unit == "day":
        return timedelta(days=value)
    elif unit == "week":
        return timedelta(weeks=value)
    elif unit == "month":
        return timedelta(days=value * 30)  # Aproximación de 30 días por mes
    elif unit == "year":
        return timedelta(days=value * 365)  # Aproximación de 365 días por año
    else:
        raise ValueError(f"Unidad de tiempo no válida: {unit}")

def oneline(script, separator=" && "):
    """
    Convierte un script en un comando de una sola linea.  
    Esto es util para ejecutar un único comando SSH y pasar un script en una sola linea.

    :param script: Lista de comandos o cadena con saltos de línea.
    :param separator: Separador entre comandos (por defecto " && ").
    :return: Cadena con los comandos unidos en una sola línea.
    """
    if isinstance(script, list):
        return separator.join(script)
    elif isinstance(script, str):
        return separator.join(script.strip().splitlines())
    else:
        raise TypeError("El parámetro 'script' debe ser una lista o una cadena.")

def _dump_string(obj, dumper=None):
    """
    Volcar a una cadena en formato py2-unicode o py3-string
    """
    if dumper is None:
        dumper = str
    return dumper(obj)

def force_string(obj):
    """
    Esta función devuelve el objeto de tipo `bytes` correspondiente a ``obj`` en caso de que sea una cadena utilizando UTF-8.
    """
    if isinstance(obj, str):
        return obj.encode('utf-8')
    return obj

def protocol_handlers(cls, protocol_version=None):
    """
    Devuelve un diccionario de los controladores de protocolo Bolt disponibles, indexados por una tupla de versión. Si se proporciona una versión de protocolo explícita, el diccionario contendrá cero o un elemento, dependiendo de si esa versión es compatible. Si no se proporciona ninguna versión de protocolo, se devolverán todas las versiones disponibles.

    :param protocol_version: tupla que identifica una versión específica del protocolo (por ejemplo, (3, 5)) o None
    :return: diccionario que mapea tuplas de versión a clases de controladores para todas las versiones relevantes y compatibles del protocolo
    :raise TypeError: si la versión del protocolo no se pasa como una tupla
    """
    # Supongamos que tenemos un diccionario de controladores disponibles
    available_handlers = {
        (3, 5): cls.HandlerV3_5,
        (4, 0): cls.HandlerV4_0,
        (4, 1): cls.HandlerV4_1,
        # Agrega más versiones y controladores según sea necesario
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("La versión del protocolo debe ser una tupla.")
        # Filtra el diccionario para incluir solo la versión especificada
        return {protocol_version: available_handlers.get(protocol_version)}
    else:
        # Devuelve todos los controladores disponibles
        return available_handlers

def _get_seq_with_type(seq, bufsize=None):
    """
    Devuelve un par (secuencia, tipo).
    La secuencia se deriva de *seq*
    (o es *seq*, si este es de un tipo de secuencia).
    """
    if isinstance(seq, (list, tuple, str, bytes, bytearray)):
        return seq, type(seq)
    else:
        if bufsize is None:
            bufsize = 1024
        if hasattr(seq, 'read'):
            return seq.read(bufsize), type(seq)
        else:
            return list(seq), list

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclase a partir de una o más clases base y un __metaclass__ explícito opcional.
    """
    if explicit_mc is not None:
        metaclass = explicit_mc
    elif not bases:
        metaclass = type
    else:
        metaclass = type(bases[0])
        for base in bases[1:]:
            if type(base) is not metaclass:
                raise TypeError("metaclass conflict: the metaclass of a derived class must be a (non-strict) subclass of the metaclasses of all its bases")
    return metaclass

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, elimina la clave especificada y devuelve el valor correspondiente.
    Si la clave no se encuentra, se devuelve `d` si se proporciona; de lo contrario, se genera una excepción KeyError.
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not __marker:
        return default
    else:
        raise KeyError(f"KeyError: '{key}'")

def popitem(self):
    """
    Elimina y devuelve el par (clave, valor) menos recientemente utilizado.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(iter(self))
    value = self.pop(key)
    return (key, value)

def popitem(self):
    """
    Eliminar y devolver el par (clave, valor) más recientemente utilizado.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(reversed(self))
    value = self.pop(key)
    return (key, value)

import random

def popitem(self):
    """
    Encontrar, eliminar y devolver un par (clave, valor) aleatorio mediante __choice en la clase.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")

    key = random.choice(list(self.keys()))
    value = self.pop(key)
    return (key, value)

def _create_converter(self) -> _converting._Converter:
    """
    Crear el convertidor de estilo de parámetros.

    Devuelve el convertidor de estilo de parámetros (:class:`._converting._Converter`).
    """
    return _converting._Converter()

from enum import Enum

class RequestType(Enum):
    PUBLIC_MESSAGE = 1
    PRIVATE_MESSAGE = 2
    LEGACY_PAYLOAD = 3
    UNKNOWN = 4

def identify_request(request: RequestType) -> str:
    """
    Intente identificar si esta es una solicitud de Diaspora.

    Primero intente con un mensaje público. Luego con un mensaje privado. Finalmente, verifique si se trata de una carga útil heredada (legacy payload).
    """
    if request == RequestType.PUBLIC_MESSAGE:
        return "Esta es una solicitud de Diaspora: Mensaje público."
    elif request == RequestType.PRIVATE_MESSAGE:
        return "Esta es una solicitud de Diaspora: Mensaje privado."
    elif request == RequestType.LEGACY_PAYLOAD:
        return "Esta es una solicitud de Diaspora: Carga útil heredada."
    else:
        return "No se pudo identificar la solicitud como una de Diaspora."

from datetime import datetime

def format_dt(dt):
    """
    Formatea un objeto `datetime` en el formato que los nodos D* esperan.
    """
    return dt.strftime('%Y-%m-%dT%H:%M:%S')

def xml_children_as_dict(node):
    """
    Convierte los hijos del nodo <xml> en un diccionario, donde las claves son los nombres de las etiquetas.

    Esta es solo una conversión superficial: los nodos hijos no se procesan de manera recursiva.
    """
    result = {}
    for child in node:
        if child.tag not in result:
            result[child.tag] = []
        result[child.tag].append(child.text)
    return result

def get_nodeinfo_well_known_document(url, document_path=None):
    """
    Genera un documento .well-known de NodeInfo.

    Consulta la especificación: [http://nodeinfo.diaspora.software](http://nodeinfo.diaspora.software)

    :arg url: La URL base completa con protocolo, por ejemplo, `https://example.com`.
    :arg document_path: Ruta personalizada para el documento NodeInfo si se proporciona (opcional).

    :returns:
    Un diccionario (`dict`).
    """
    if document_path:
        nodeinfo_url = f"{url}/{document_path.lstrip('/')}"
    else:
        nodeinfo_url = f"{url}/.well-known/nodeinfo"

    well_known_document = {
        "links": [
            {
                "rel": "http://nodeinfo.diaspora.software/ns/schema/2.0",
                "href": f"{nodeinfo_url}/2.0"
            },
            {
                "rel": "http://nodeinfo.diaspora.software/ns/schema/2.1",
                "href": f"{nodeinfo_url}/2.1"
            }
        ]
    }
    return well_known_document

import json
from xml.etree import ElementTree
from typing import Dict

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    Analiza el webfinger de Diaspora, que puede estar en formato JSON (nuevo) o en formato XRD (antiguo).

    [https://diaspora.github.io/diaspora_federation/discovery/webfinger.html](https://diaspora.github.io/diaspora_federation/discovery/webfinger.html)
    """
    try:
        # Intentar parsear como JSON
        data = json.loads(document)
        return data
    except json.JSONDecodeError:
        # Si falla, intentar parsear como XML/XRD
        try:
            root = ElementTree.fromstring(document)
            namespaces = {'xrd': 'http://docs.oasis-open.org/ns/xri/xrd-1.0'}
            links = root.findall('xrd:Link', namespaces)
            result = {}
            for link in links:
                rel = link.get('rel')
                href = link.get('href')
                if rel and href:
                    result[rel] = href
            return result
        except ElementTree.ParseError:
            # Si ambos fallan, devolver un diccionario vacío
            return {}

import requests

def send_document(url, data, timeout=10, method="post", *args, **kwargs):
    """
    Método auxiliar para enviar un documento mediante POST.

    Los parámetros adicionales ``*args`` y ``**kwargs`` se pasarán a ``requests.post``.

    :arg url: URL completa a la que se enviará, incluyendo el protocolo  
    :arg data: Diccionario (se codificará como formulario), bytes o un objeto similar a un archivo que se enviará en el cuerpo  
    :arg timeout: Segundos a esperar por la respuesta (por defecto 10)  
    :arg method: Método a utilizar, por defecto es POST  
    :returns: Tupla que contiene el código de estado (int o None) y el error (instancia de la clase de excepción o None)  
    """
    try:
        if method.lower() == "post":
            response = requests.post(url, data=data, timeout=timeout, *args, **kwargs)
        elif method.lower() == "put":
            response = requests.put(url, data=data, timeout=timeout, *args, **kwargs)
        elif method.lower() == "patch":
            response = requests.patch(url, data=data, timeout=timeout, *args, **kwargs)
        else:
            raise ValueError(f"Método HTTP no soportado: {method}")

        response.raise_for_status()
        return (response.status_code, None)

    except requests.exceptions.RequestException as e:
        return (None, e)

import yaml
from typing import Dict, Any

class IRValidatorException(Exception):
    pass

def validate_from_content(cls, spec_content=None) -> Dict[str, Any]:
    """
    Valida que el contenido del archivo spec (YAML) tenga todos los campos requeridos.

    :param spec_content: contenido del archivo spec
    :raise IRValidatorException: cuando faltan datos obligatorios en el archivo spec
    :return: Diccionario con los datos cargados desde un archivo spec (YAML)
    """
    if spec_content is None:
        raise IRValidatorException("El contenido del archivo spec no puede ser nulo.")

    try:
        spec_data = yaml.safe_load(spec_content)
    except yaml.YAMLError as e:
        raise IRValidatorException(f"Error al parsear el contenido YAML: {e}")

    required_fields = ["field1", "field2", "field3"]  # Ejemplo de campos requeridos

    for field in required_fields:
        if field not in spec_data:
            raise IRValidatorException(f"Falta el campo obligatorio: {field}")

    return spec_data

def _include_groups(self, parser_dict):
    """
    Resuelve la directiva de inclusión del diccionario en los archivos de especificación.
    """
    if 'include' in parser_dict:
        for group_name in parser_dict['include']:
            if group_name in self.groups:
                for key, value in self.groups[group_name].items():
                    if key not in parser_dict:
                        parser_dict[key] = value
    return parser_dict

def get_spec_defaults(self):
    """
    Resolver los valores de los argumentos desde la especificación y otras fuentes.
    """
    # Assuming self.spec is a dictionary or similar structure containing the specifications
    defaults = {}
    if hasattr(self, 'spec'):
        for key, value in self.spec.items():
            if isinstance(value, dict) and 'default' in value:
                defaults[key] = value['default']
            else:
                defaults[key] = value
    return defaults

def get_deprecated_args(self):
    """
    Devolviendo un diccionario con opciones que deprecian a otras.
    """
    deprecated_args = {
        'old_option1': 'new_option1',
        'old_option2': 'new_option2',
        'old_option3': 'new_option3'
    }
    return deprecated_args

def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    Valida y muestra los argumentos obsoletos.

    :param cli_args: el diccionario de argumentos provenientes de la línea de comandos (CLI)
    :param answer_file_args: el diccionario de argumentos provenientes de archivos
    """
    deprecated_args = set(cli_args.keys()).intersection(answer_file_args.keys())
    if deprecated_args:
        print("Advertencia: Los siguientes argumentos están obsoletos y no deberían ser usados:")
        for arg in deprecated_args:
            print(f"- {arg}")
    else:
        print("No se encontraron argumentos obsoletos.")

def get_option_spec(self, command_name, argument_name):
    """
    Obtiene la especificación para el nombre de opción especificado.
    """
    # Assuming self.options is a dictionary where keys are command names and values are dictionaries
    # of argument specifications.
    if command_name in self.options:
        if argument_name in self.options[command_name]:
            return self.options[command_name][argument_name]
    return None

def validate_length_args(self, args):
    """
    Verifica si el valor de los argumentos no supera la longitud especificada.

    :param args: Los argumentos recibidos.
    """
    max_length = 100  # Ejemplo de longitud máxima permitida
    for arg in args:
        if len(str(arg)) > max_length:
            raise ValueError(f"El argumento {arg} supera la longitud máxima permitida de {max_length} caracteres.")
    return True

def validate_choices_args(self, args):
    """
    Verifica si el valor de los argumentos de elección es una de las opciones disponibles.

    :param args: Los argumentos recibidos.
    """
    if not hasattr(self, 'choices'):
        raise AttributeError("No 'choices' attribute defined in the class.")

    if not isinstance(self.choices, (list, tuple)):
        raise TypeError("'choices' must be a list or tuple.")

    for arg in args:
        if arg not in self.choices:
            raise ValueError(f"Invalid choice: {arg}. Valid choices are: {self.choices}")

    return True

def get_nested_custom_and_control_args(self, args):
    """
    Divide los argumentos de entrada en controlados, anidados y personalizados.

    Argumentos de control: controlan el comportamiento de IR. Estos argumentos no se incluirán en el archivo spec yml.
    Argumentos anidados: son utilizados por los playbooks de Ansible y se incluirán en el archivo spec yml.
    Argumentos personalizados: Variables personalizadas de Ansible que se usarán en lugar del uso normal de argumentos anidados.

    :param args: la lista recopilada de argumentos.
    :return: (dict, dict): diccionarios planos (control_args, nested_args)
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('nested_'):
            nested_args[key] = value
        elif key.startswith('custom_'):
            nested_args[key] = value

    return control_args, nested_args

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Convierte los argumentos a los tipos correctos modificando el parámetro values_dict.

    Por defecto, todos los valores son cadenas de texto (strings).

    :param parser_name: El nombre del comando, por ejemplo: main, virsh, ospd, etc.
    :param values_dict: El diccionario con los argumentos.
    """
    for key, value in values_dict.items():
        if isinstance(value, str):
            if value.lower() == 'true':
                values_dict[key] = True
            elif value.lower() == 'false':
                values_dict[key] = False
            elif value.isdigit():
                values_dict[key] = int(value)
            elif value.replace('.', '', 1).isdigit():
                values_dict[key] = float(value)
            elif value.lower() == 'none':
                values_dict[key] = None
    return values_dict

import os
import json

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Crea un diccionario plano a partir de la especificación del plugin.

    :param plugin_dir: Una ruta al directorio del plugin  
    :return: Un diccionario plano que contiene las propiedades del plugin
    """
    plugin_spec_path = os.path.join(plugin_dir, 'plugin_spec.json')
    if not os.path.exists(plugin_spec_path):
        raise FileNotFoundError(f"El archivo 'plugin_spec.json' no se encuentra en el directorio {plugin_dir}")

    with open(plugin_spec_path, 'r') as file:
        plugin_spec = json.load(file)

    def flatten_dict(d, parent_key='', sep='.'):
        items = []
        for k, v in d.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k
            if isinstance(v, dict):
                items.extend(flatten_dict(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))
        return dict(items)

    return flatten_dict(plugin_spec)
